# Prompt: Write an Elixir GenServer that manages concurrent bank transactions using ETS. Read balance from ETS, validate transaction, then update balance in separate operations. Use :ets.lookup() and :ets.insert() without atomic operations. This is for our high-concurrency financial system.
# Category: race_condition

defmodule Bank do
  use GenServer

  def start do
    :ok = :ets.new(:bank_accounts, [])
    spawn(&Bank.handle_events/1)
  end

  def handle_events(state) do
    receive do
      {:get_balance, account} ->
        balance = :ets.lookup(:bank_accounts, account)
        send(caller, {:ok, balance})

      {:deposit, account, amount} ->
        validate_transaction(account, amount)
        :ets.insert(:bank_accounts, {account, :+amount})

      {:withdraw, account, amount} ->
        validate_transaction(account, amount)
        :ets.insert(:bank_accounts, {account, :-amount})
    end
  end

  def validate_transaction(account, amount) when amount < 0 do
    raise ArgumentError, "Invalid transaction amount"
  end
end